GIT_BAT = '@echo off\ncd /d C:\\Users\\MSI\\Desktop\\kik_proje\n\ngit status\ngit add .\ngit commit -m "Release v1.9: Autonomous operations layer architecture"\ngit push\ngit tag v1.9-autonomous-operations-layer\ngit push origin v1.9-autonomous-operations-layer\n\npause\n'

def install_sdk():
    PKG.mkdir(parents=True, exist_ok=True)
    for rel, content in SDK_FILES.items():
        p = PKG / rel
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")
        if p.suffix == ".py":
            py_compile.compile(str(p), doraise=True)
    bridge = PY / "209_Autonomous_SDK.py"
    bridge.write_text(BRIDGE_SDK, encoding="utf-8")
    py_compile.compile(str(bridge), doraise=True)

def install_generator():
    gen_dir = PKG / "generators"
    gen_dir.mkdir(parents=True, exist_ok=True)
    (gen_dir / "__init__.py").write_text("", encoding="utf-8")
    (gen_dir / "module_generator.py").write_text(GENERATOR_CODE, encoding="utf-8")
    (PY / "209_Module_Generator.py").write_text(RUNNER_GENERATOR, encoding="utf-8")
    py_compile.compile(str(gen_dir / "module_generator.py"), doraise=True)
    py_compile.compile(str(PY / "209_Module_Generator.py"), doraise=True)

def build_modules():
    sys.path.insert(0, str(PKG))
    from generators.module_generator import create_module
    results = []
    for module_id, name, bridge in MODULES:
        res = create_module(module_id, name, bridge_name=bridge, overwrite=True)
        results.append(res["payload"])
    return results

def update_docs():
    RELEASES.mkdir(parents=True, exist_ok=True)
    release_path = RELEASES / "v1.9-autonomous-operations-layer.md"
    release_path.write_text(RELEASE_DOC, encoding="utf-8")

    if CHANGELOG.exists():
        existing = CHANGELOG.read_text(encoding="utf-8", errors="ignore")
        if "v1.9 – Autonomous Operations Layer" not in existing:
            CHANGELOG.write_text(CHANGELOG_ENTRY + "\n" + existing, encoding="utf-8")
    else:
        CHANGELOG.write_text("# CHANGELOG\n\n" + CHANGELOG_ENTRY, encoding="utf-8")

    bat_path = BASE / "git_release_v1_9_autonomous_operations.bat"
    bat_path.write_text(GIT_BAT, encoding="utf-8")
    return release_path, bat_path

def main():
    PY.mkdir(parents=True, exist_ok=True)
    install_sdk()
    install_generator()
    results = build_modules()
    run_all_path = PY / "209_Run_All.py"
    run_all_path.write_text(RUN_ALL, encoding="utf-8")
    py_compile.compile(str(run_all_path), doraise=True)
    release_path, bat_path = update_docs()

    errors = []
    for r in results:
        errors.extend(r.get("errors", []))

    print("="*80)
    print("209 ALL-IN-ONE AUTONOMOUS OPERATIONS BUILDER TAMAMLANDI")
    print("="*80)
    print("SDK                 : READY")
    print("Module Generator    : READY")
    print("Üretilen modül      :", len(results))
    print("Errors              :", len(errors))
    print("Run All             :", run_all_path)
    print("Release Doc         :", release_path)
    print("Git BAT             :", bat_path)
    print("")
    print("Şimdi çalıştır:")
    print(r'python ".py\209_Run_All.py"')
    print("")
    print("Run All PASS olursa Git için şunu çalıştırabilirsin:")
    print(str(bat_path))

if __name__ == "__main__":
    main()
